mapper.select:
    	SELECT cr.room_id
    	FROM chat_rooms cr
    	WHERE cr.room_type = 'DM'

      	AND EXISTS (
          	SELECT 1 FROM chat_room_members 
          	WHERE room_id = cr.room_id AND account_id = #{accountId1}
	      )

	      AND EXISTS (
	          SELECT 1 FROM chat_room_members 
	          WHERE room_id = cr.room_id AND account_id = #{accountId2}
	      )

	      AND (
	          SELECT COUNT(*) FROM chat_room_members 
	          WHERE room_id = cr.room_id
	      ) = 2
	      AND ROWNUM = 1

mapper.update:
UPDATE chat_room_members 
SET last_read_message_id = #{messageId}
WHERE room_id = #{roomId} 
  AND account_id = #{accountId}

mapper.select:
SELECT account_id
FROM chat_room_members
WHERE room_id = #{roomId}
  AND account_id != #{myId}
  AND ROWNUM = 1

mapper.update:
UPDATE chat_room_members
SET is_hidden = 'Y'
WHERE room_id = #{roomId}
  AND account_id = #{accountId}

mapper.select:
SELECT NVL(is_muted, 0)
FROM chat_room_notifications
WHERE room_id = #{roomId}
  AND account_id = #{accountId}

SELECT NVL(
    (SELECT MAX(cm.message_id)
     FROM chat_messages cm
     WHERE cm.room_id = #{roomId}
       AND cm.sender_account_id = #{myId}
       AND cm.message_id <= (
           SELECT NVL(crm.last_read_message_id, 0)
           FROM chat_room_members crm
           WHERE crm.room_id = #{roomId}
             AND crm.account_id = #{otherAccountId}
       )
    ), 0
) AS lastReadMyMessageId
FROM DUAL

SELECT room_id
FROM chat_messages
WHERE message_id = #{messageId}

mapper.update:
UPDATE chat_messages
SET is_deleted = 'Y'
WHERE message_id = #{messageId}
